// Branchless clamp: result = (val < max) ? val : max
// xor(val, mul(xor(val, max), lt(max, val)))
// When val <= max: lt=0, mul=0, xor with 0 = val unchanged
// When val > max:  lt=1, mul=xor(val,max), xor cancels to max
assembly {
    let n := mload(b)
    end   := xor(end,   mul(xor(end,   n), lt(n, end)))
    start := xor(start, mul(xor(start, n), lt(n, start)))
    result := keccak256(add(add(b, 0x20), start), mul(gt(end, start), sub(end, start)))
}
